#!/bin/bash
whois holbertonschool.com | awk -F: 'BEGIN{split("Registrant Name|Registrant Organization|Registrant Street|Registrant City|Registrant State/Province|Registrant Postal Code|Registrant Country|Registrant Phone|Registrant Phone Ext:|Registrant Fax|Registrant Fax Ext:|Registrant Email|Admin Name|Admin Organization|Admin Street|Admin City|Admin State/Province|Admin Postal Code|Admin Country|Admin Phone|Admin Phone Ext:|Admin Fax|Admin Fax Ext:|Admin Email|Tech Name|Tech Organization|Tech Street|Tech City|Tech State/Province|Tech Postal Code|Tech Country|Tech Phone|Tech Phone Ext:|Tech Fax|Tech Fax Ext:|Tech Email",f,"|")} {k=$1; gsub(/^[ \t]+|[ \t]+$/,"",k); v=$2; gsub(/^[ \t]+|[ \t]+$/,"",v); for(i=1;i<=36;i++){c=f[i]; sub(/:$/,"",c); if(k==c)d[i]=v}} END{for(i=1;i<=36;i++){printf "%s,%s",f[i],d[i]; if(i<36)printf "\n"}}'
